**Note:** As an AI text model, I cannot directly generate or render a 3D image file (like .obj, .fbx, or a PNG). However, I can provide you with the **exact code** to render a 3D house using **Three.js** (a popular JavaScript 3D library).

You can run this code immediately in your browser.

### How to use this:
1.  Create a new file on your computer named `house.html`.
2.  Paste the code below into that file.
3.  Open `house.html` in any web browser (Chrome, Firefox, Edge).

### The Code (Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.8 });
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xF5F5DC, roughness: 0.5 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // A. Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // B. Main Body
        const bodyGeo = new THREE.BoxGeometry(10, 6, 10);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // C. Roof
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // D. Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 5.25); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // E. Windows (Simple squares)
        const windowGeo = new THREE.BoxGeometry(2, 2, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(-2.5, 4, 5.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(2.5, 4, 5.1);
        houseGroup.add(win2);

        // Side Window
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(0, 4, -4.9);
        houseGroup.add(win3);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Sets up a Scene:** Creates a 3D environment with a sky-blue background and fog.
2.  **Creates Lighting:** Adds a directional light (sun) that casts shadows and an ambient light for general visibility.
3.  **Constructs the House:**
    *   **Body:** A beige box.
    *   **Roof:** A brown cone rotated to sit on top of the box.
    *   **Details:** Adds a black door and blue transparent windows.
4.  **Interaction:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.

### Want to make it more realistic?
If you want to render a photorealistic house (with textures, trees, and complex geometry), you would typically use a dedicated 3D software like **Blender** or **Unreal Engine** and export the file as a `.glb` or `.gltf` file, which can then be loaded into a web viewer. The code above is a "procedural" generation, meaning it builds the house using math rather than loading a pre-made model.
